3	public class Solution {
4	    // Optimal: monotonic increasing stack of indices. O(n) time, O(n) space.
5	    public int largestRectangleArea(int[] heights) {
6	        if (heights == null || heights.length == 0) {
7	            return 0;
8	        }
9	
10	        int n = heights.length;
11	        long maxArea = 0;
12	        Deque<Integer> stack = new ArrayDeque<>(); // holds indices, heights increasing
13	
14	        // Iterate one past the end with a virtual zero-height bar to flush the stack.
15	        for (int rightIndex = 0; rightIndex <= n; rightIndex++) {
16	            int currentHeight = (rightIndex == n) ? 0 : heights[rightIndex];
17	
18	            // While the current bar is shorter than the bar on top of the stack,
19	            // that taller bar can't extend further right — finalize its rectangle.
20	            while (!stack.isEmpty() && heights[stack.peek()] >= currentHeight) {
21	                int poppedHeight = heights[stack.pop()];
22	                // Left boundary is the new top after popping (exclusive); right is rightIndex (exclusive).
23	                int leftBoundary = stack.isEmpty() ? -1 : stack.peek();
24	                long width = rightIndex - leftBoundary - 1;
25	                long area = (long) poppedHeight * width;
26	                maxArea = Math.max(maxArea, area);
27	            }
28	            stack.push(rightIndex);
29	        }
30	
31	        return (int) maxArea;
32	    }
33	
34	    // Brute force oracle: O(n^2). For each bar, expand left/right while >= its height.
35	    public int largestRectangleAreaBrute(int[] heights) {
36	        if (heights == null || heights.length == 0) {
37	            return 0;
38	        }
39	        int n = heights.length;
40	        long maxArea = 0;
41	        for (int i = 0; i < n; i++) {
42	            int h = heights[i];
43	            int left = i;
44	            while (left - 1 >= 0 && heights[left - 1] >= h) {
45	                left--;
46	            }
47	            int right = i;
48	            while (right + 1 < n && heights[right + 1] >= h) {
49	                right++;
50	            }
51	            long width = right - left + 1;
52	            maxArea = Math.max(maxArea, (long) h * width);
53	        }
54	        return (int) maxArea;
55	    }
56	}
