4	    public static void main(String[] args) {
5	        Solution sol = new Solution();
6	        boolean allPass = true;
7	
8	        // Test 1: LeetCode example -> 10
9	        allPass &= check(sol, new int[]{2, 1, 5, 6, 2, 3}, 10, "example");
10	
11	        // Test 2: single bar
12	        allPass &= check(sol, new int[]{5}, 5, "single bar");
13	
14	        // Test 3: single zero bar
15	        allPass &= check(sol, new int[]{0}, 0, "single zero");
16	
17	        // Test 4: empty
18	        allPass &= check(sol, new int[]{}, 0, "empty");
19	
20	        // Test 5: all equal -> n * h
21	        allPass &= check(sol, new int[]{3, 3, 3, 3}, 12, "all equal");
22	
23	        // Test 6: strictly increasing -> best is last bar alone vs full width
24	        allPass &= check(sol, new int[]{1, 2, 3, 4, 5}, 9, "increasing");
25	
26	        // Test 7: strictly decreasing
27	        allPass &= check(sol, new int[]{5, 4, 3, 2, 1}, 9, "decreasing");
28	
29	        // Test 8: contains zeros splitting the histogram
30	        allPass &= check(sol, new int[]{2, 0, 2}, 2, "zeros split");
31	
32	        // Test 9: two bars
33	        allPass &= check(sol, new int[]{2, 4}, 4, "two bars");
34	
35	        // Test 10: valley shape
36	        allPass &= check(sol, new int[]{6, 2, 5, 4, 5, 1, 6}, 12, "valley");
37	
38	        // Test 11: all zeros
39	        allPass &= check(sol, new int[]{0, 0, 0}, 0, "all zeros");
40	
41	        // Test 12: overflow guard — large heights and width
42	        // 100000 bars of height 10000 -> area 1,000,000,000 (fits in int but near edge)
43	        int[] big = new int[100000];
44	        Arrays.fill(big, 10000);
45	        allPass &= check(sol, big, 1000000000, "max-area overflow guard");
46	
47	        // Stress: brute-force oracle vs optimal on random inputs
48	        Random rng = new Random(42);
49	        for (int t = 0; t < 5000; t++) {
50	            int len = rng.nextInt(12) + 1;
51	            int[] arr = new int[len];
52	            for (int j = 0; j < len; j++) {
53	                arr[j] = rng.nextInt(6); // small values incl 0 for collisions
54	            }
55	            int opt = sol.largestRectangleArea(arr.clone());
56	            int brute = sol.largestRectangleAreaBrute(arr.clone());
57	            if (opt != brute) {
58	                allPass = false;
59	                System.out.println("STRESS MISMATCH " + Arrays.toString(arr)
60	                        + " opt=" + opt + " brute=" + brute);
61	            }
62	        }
63	
64	        // Large stress for performance/no-crash at constraint size
65	        int[] perf = new int[100000];
66	        for (int i = 0; i < perf.length; i++) {
67	            perf[i] = rng.nextInt(10001);
68	        }
69	        long start = System.nanoTime();
70	        int perfRes = sol.largestRectangleArea(perf);
71	        long ms = (System.nanoTime() - start) / 1_000_000;
72	        System.out.println("perf n=100000 result=" + perfRes + " time=" + ms + "ms");
73	
74	        System.out.println(allPass ? "ALL TESTS PASSED" : "SOME TESTS FAILED");
75	    }
76	
77	    private static boolean check(Solution sol, int[] heights, int expected, String name) {
78	        int got = sol.largestRectangleArea(heights.clone());
79	        boolean ok = got == expected;
80	        System.out.println((ok ? "PASS" : "FAIL") + " [" + name + "] expected="
81	                + expected + " got=" + got);
82	        return ok;
83	    }
84	}
