import java.util.*;
public class Probe {
    public static void main(String[] args) {
        Solution sol = new Solution();
        // 1. Exact max-constraint: n=100000, all height=10000 -> area = 1e9
        int[] maxc = new int[100000];
        Arrays.fill(maxc, 10000);
        System.out.println("max constraint area = " + sol.largestRectangleArea(maxc) + " (expect 1000000000)");

        // 2. Beyond-constraint overflow probe: n=200000, h=20000 -> area = 4e9 > int max
        // This tests whether the final (int) cast silently truncates if inputs exceed stated bounds.
        int[] over = new int[200000];
        Arrays.fill(over, 20000);
        long expected = 200000L * 20000L; // 4,000,000,000
        System.out.println("over-constraint long area would be = " + expected);
        System.out.println("over-constraint returned (int)     = " + sol.largestRectangleArea(over));

        // 3. Path not through root analogy n/a (array). Try monotone equal plateau with one taller spike.
        int[] spike = {1,1,1,10000,1,1,1};
        System.out.println("spike = " + sol.largestRectangleArea(spike) + " brute=" + sol.largestRectangleAreaBrute(spike));

        // 4. Exhaustive small-input oracle: all arrays length 1..8 over values 0..3
        int mismatches = 0;
        for (int len = 1; len <= 8; len++) {
            int total = (int) Math.pow(4, len);
            for (int code = 0; code < total; code++) {
                int[] a = new int[len];
                int c = code;
                for (int k = 0; k < len; k++) { a[k] = c % 4; c /= 4; }
                int opt = sol.largestRectangleArea(a.clone());
                int br  = sol.largestRectangleAreaBrute(a.clone());
                if (opt != br) { mismatches++; if (mismatches<=5) System.out.println("MISMATCH "+Arrays.toString(a)+" opt="+opt+" brute="+br); }
            }
        }
        System.out.println("exhaustive mismatches (len 1..8, vals 0..3) = " + mismatches);
    }
}
